// src/components/Header.js
import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

// Exemplo de ícone de avatar (pode trocar por imagem sua)
// Vou usar um SVG simples de “usuário” (pode ficar em linha ou importar de outro lugar):
const AvatarIcon = () => (
  <svg
    xmlns="http://www.w3.org/2000/svg"
    className="h-8 w-8 text-gray-700"
    fill="none"
    viewBox="0 0 24 24"
    stroke="currentColor"
  >
    <path
      strokeLinecap="round"
      strokeLinejoin="round"
      strokeWidth={2}
      d="M5.121 17.804A9 9 0 1116.88 6.195M15 11a3 3 0 11-6 0 3 3 0 016 0z"
    />
  </svg>
);

export default function Header() {
  const [dropdownOpen, setDropdownOpen] = useState(false);
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  // Alterna visibilidade do dropdown
  const toggleDropdown = () => {
    setDropdownOpen(prev => !prev);
  };

  // Função para ir ao perfil do aluno logado
  const handlePerfil = () => {
    setDropdownOpen(false);
    // Se você tiver uma rota dedicada para editar perfil, por exemplo "/perfil",
    // basta navegar para ela. Se quiser usar a tela de FormAluno passando
    // o próprio ID, seria algo como: navigate(`/alunos/${user.id}/editar`).
    navigate('/perfil');
  };

  // Função para sair
  const handleLogout = () => {
    setDropdownOpen(false);
    logout();
    navigate('/login', { replace: true });
  };

  // Opicional: fechar o dropdown se clicar fora (bastante útil)
  // Podemos adicionar um listener no document, mas para manter simples:
  // se o usuário clicar em qualquer outra parte da página (exceto no 
  // próprio dropdown), podemos forçar fechar. Isso requer um pouco mais de
  // código, mas não é obrigatório — deixarei de fora para simplificar.

  return (
    <header className="fixed top-0 left-0 right-0 h-16 bg-white shadow flex items-center justify-between px-6 z-50">
      {/* LOGO ou título */}
      <div className="flex items-center">
        <h1 className="text-xl font-bold text-[#3172C0]">Minha App</h1>
      </div>

      {/* Área do avatar e dropdown */}
      <div className="relative">
        {/* Botão do Avatar */}
        <button
          onClick={toggleDropdown}
          className="rounded-full focus:outline-none focus:ring-2 focus:ring-blue-400"
        >
          <AvatarIcon />
        </button>

        {/* Dropdown */}
        {dropdownOpen && (
          <ul className="absolute right-0 mt-2 w-48 bg-white border border-gray-200 rounded-lg shadow-lg">
            {/* Exibir o nome do usuário logado */}
            <li className="px-4 py-2 text-gray-700 font-medium border-b border-gray-100">
              {user?.usuario || 'Usuário'}
            </li>

            {/* Opção “Meu Perfil” */}
            <li>
              <button
                onClick={handlePerfil}
                className="w-full text-left px-4 py-2 hover:bg-gray-100 text-gray-700"
              >
                Meu Perfil
              </button>
            </li>

            {/* Espaço opcional para inserir outras opções, ex: Configurações */}
            {/* Exemplo:
            <li>
              <button
                onClick={() => { /* alguma ação *\/ }}
                className="w-full text-left px-4 py-2 hover:bg-gray-100 text-gray-700"
              >
                Configurações
              </button>
            </li>
            */}

            {/* Opção “Sair” */}
            <li>
              <button
                onClick={handleLogout}
                className="w-full text-left px-4 py-2 hover:bg-gray-100 text-red-600"
              >
                Sair
              </button>
            </li>
          </ul>
        )}
      </div>
    </header>
  );
}
